/* ── Public API ──────────────────────────────────────────────────────────── */

audio_clip_t clip_for_char(char c)
{
    if (c >= '0' && c <= '9') {
        return s_digit_clips[c - '0'];
    }
    if (c >= 'A' && c <= 'Z') {
        return s_letter_clips[c - 'A'];
    }
    if (c >= 'a' && c <= 'z') {
        return s_letter_clips[c - 'a'];
    }
    audio_clip_t empty = { NULL, 0 };
    return empty;
}
